import{_ as r,c as t,l as a,a as o,t as i,a4 as n,o as l}from"./chunks/framework.CzsDe1xi.js";const k=JSON.parse('{"title":"@Transcation注解事务不生效场景","description":"","frontmatter":{"title":"@Transcation注解事务不生效场景"},"headers":[],"relativePath":"doc/编程语言/后端/Java/业务框架/Spring/Transcation注解事务不生效场景.md","filePath":"packages/doc/src/编程语言/后端/Java/业务框架/Spring/Transcation注解事务不生效场景.md","lastUpdated":1715528341000}'),s={name:"doc/编程语言/后端/Java/业务框架/Spring/Transcation注解事务不生效场景.md"},c={id:"frontmatter-title",tabindex:"-1"},p=a("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),h=n('<h2 id="数据库引擎不支持事务" tabindex="-1">数据库引擎不支持事务 <a class="header-anchor" href="#数据库引擎不支持事务" aria-label="Permalink to &quot;数据库引擎不支持事务&quot;">​</a></h2><p>mysql的ISAM不支持事务</p><h2 id="被注解的方法为私有方法private" tabindex="-1">被注解的方法为私有方法private <a class="header-anchor" href="#被注解的方法为私有方法private" aria-label="Permalink to &quot;被注解的方法为私有方法private&quot;">​</a></h2><p>Spring的事务代理通常是通过Java动态代理或CGLIB动态代理生成的，这些代理要求目标方法是公开可访问的（public）。私有方法无法被代理，因此事务将无效。</p><h2 id="注解的方法所属的类没有被spring管理" tabindex="-1">注解的方法所属的类没有被spring管理 <a class="header-anchor" href="#注解的方法所属的类没有被spring管理" aria-label="Permalink to &quot;注解的方法所属的类没有被spring管理&quot;">​</a></h2><p>比如所在类没有使用@Controller,@Service,@Componment，@Bean等注解</p><p>Spring的事务管理需要在Spring容器中配置的Bean上才能生效。如果目标类没有被配置为Spring Bean，那么事务将无法被应用。</p><h2 id="注解的方法被标注为final类型" tabindex="-1">注解的方法被标注为final类型 <a class="header-anchor" href="#注解的方法被标注为final类型" aria-label="Permalink to &quot;注解的方法被标注为final类型&quot;">​</a></h2><p>由于底层使用了动态代理，如果设置为final就表示不能生成动态代理对象</p><h2 id="注解的属性rollbackfor异常类设置错误" tabindex="-1">注解的属性rollbackFor异常类设置错误 <a class="header-anchor" href="#注解的属性rollbackfor异常类设置错误" aria-label="Permalink to &quot;注解的属性rollbackFor异常类设置错误&quot;">​</a></h2><p>@Transactional注解默认处理运行时异常，即只有抛出运行时异常，才会触发事务回滚。</p><p>默认是RuntimeException以及子类，如果需要支持其他异常需要指明在rollbackFor属性内</p><h2 id="注解的属性propagation设置错误" tabindex="-1">注解的属性propagation设置错误 <a class="header-anchor" href="#注解的属性propagation设置错误" aria-label="Permalink to &quot;注解的属性propagation设置错误&quot;">​</a></h2><p>默认是REQUIRE，如果设置为NOT_SUPPORT，会因为有事务抛出异常，如果是MANDATORY 则会因为外层没有事务的话导致报错</p><h2 id="注解的方法内异常被手动捕获" tabindex="-1">注解的方法内异常被手动捕获 <a class="header-anchor" href="#注解的方法内异常被手动捕获" aria-label="Permalink to &quot;注解的方法内异常被手动捕获&quot;">​</a></h2><p>底层是方法根据抛出的异常决定是否回滚，如果被捕获了，没有抛出，外层自然拿不到异常</p><h2 id="同一个方法内自调用-导致失效" tabindex="-1">同一个方法内自调用，导致失效 <a class="header-anchor" href="#同一个方法内自调用-导致失效" aria-label="Permalink to &quot;同一个方法内自调用，导致失效&quot;">​</a></h2><h2 id="注解的方法内部采用了多线程调用" tabindex="-1">注解的方法内部采用了多线程调用 <a class="header-anchor" href="#注解的方法内部采用了多线程调用" aria-label="Permalink to &quot;注解的方法内部采用了多线程调用&quot;">​</a></h2><p>根据事务底层原理，即子线程的状态，主流程线程不能影响到</p><h2 id="嵌套事务导致回滚失效" tabindex="-1">嵌套事务导致回滚失效 <a class="header-anchor" href="#嵌套事务导致回滚失效" aria-label="Permalink to &quot;嵌套事务导致回滚失效&quot;">​</a></h2><p>根据嵌套事务定义，内存事务回滚不会导致外层事务回滚，外层事务回滚，内存事务也会回滚</p>',21);function d(e,_,f,b,m,u){return l(),t("div",null,[a("h1",c,[o(i(e.$frontmatter.title)+" ",1),p]),h])}const g=r(s,[["render",d]]);export{k as __pageData,g as default};
